INSERT INTO recipes VALUES(1,'Biquinis','Hacer en la sandwichera','cena,rápido',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(2,'Fajitas','Cortar el tomate y el aguacate, y listos.','cena,rápido',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(3,'Pizza',replace('Poner los ingredientes en la mezcladora (en orden) y amasar durante 5-10 minutos.\n\nDejar reposar 20 minutos en el horno, a 30 ºC.\n\nDesgasificar amasando 30 segundos, y dejar reposar 40 minutos más.\n\nCuando acabe, sacar la masa a una superficie enharinada, amasar un poco enharinando un poco más hasta que no se pegue, dividirla en las porciones que queramos, opcionalmente dejar reposar 5 minutos, y darles forma con un rodillo.\n\nHornear 12-14 minutos a 220 ºC, con fuego arriba y abajo.','\n',char(10)),'cena,finde,horno,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(4,'Tortilla de patata',replace('Pelar patatas y cortarlas pequeñas, ponerlas en una sartén mediana (24 cm) hasta llenarla. \nFreír las patatas en una sartén más grande (26-28 cm) a fuego fuerte, y mientras fríe mezclar 6 huevos batidos en un cuenco de cristal grande. \nMezclar todo y salar, poner la mezcla en la sartén mediana, y cuajarla poniéndola (tapada) a fuego 5 como 5 minutos, luego girar con un plato o giratortillas, y hacer por el otro lado.','\n',char(10)),'cena,día antes,excursión,huevos,mirela,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(5,'Pasta boloñesa','','comida,carne,día antes,pasta,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(6,'Pollo Tikka Masala',replace('Mezclar en un bol la sal, garam masala, comino, cilantro en polvo, pimentón, cúrcuma, pimienta negra, cayena en polvo y cardamomo. \nEn otro bol grande, poner el pollo con el aceite y untarlo bien. \nEchar la mezcla de especias, y asegurarse de que todos los trozos están bien untados. Probar de envasar al vacío.\nDerretir el ghee/mantequilla, y ponerlo en una olla grande con el fuego alto. Freír 5-10 minutos los trozos de pollo, hasta que estén bien dorados. \nSacar y, cuando estén fríos, cortar en tamaño bocado. \nAñadir a la olla la cebolla en trozos grandes, y cocinar a fuego medio hasta que empiece a estar translúcida. \nAñadir la pasta de tomate, dejar 5 minutos hasta que caramelice, y añadir los ajos cortados finos y el jengibre rallado. \nDejar unos minutos hasta que el ajo se cocine un poco, y añadir los tomates troceados. Aprovechar para rascar bien el fondo de la olla. \nAñadir la leche de coco y el caldo, y dejar hervir a fuego suave 15 minutos, hasta que reduzca.\nAñadir el pollo cortado y el cilantro troceado, y dejar 15 minutos más, corrigiendo la sal si es necesario. \n\nAcompañar de arroz basmati.','\n',char(10)),'comida,arroz,carne,congelable,día antes,finde,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(7,'Salmón a la plancha','Hacer a la plancha','comida,pescado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(8,'Merluza rebozada',replace('Enharinar los filetes\nCalentar aceite y batir los huevos\nUntar los filetes enharinados en el huevo, y rebozar','\n',char(10)),'cena,mirela,pescado,rebozado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(9,'Pollo a la plancha','Calentar la plancha, y hacer el pollo a la plancha rociándole limón','cena,arroz,carne,día antes,rápido,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(10,'Varitas de merluza',replace('Calentar el horno\nHacer las varitas','\n',char(10)),'cena,horno,pescado,rápido,rebozado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(11,'Lubina a la plancha','Hacer a la plancha','cena,pescado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(12,'Pa amb oli','Fregar el tomate en el pan, y comer','cena,rápido',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(13,'Lentejas',replace('Si es posible, poner las lentejas en remojo la noche antes (al menos 10h). \nEscurrirlas, ponerlas en la olla y poner el caldo. Debe quedar hasta el nivel de las lentejas más dos dedos. \nPoner la cebolla entera, los ajos pelados enteros, la zanahoria a rodajas, el laurel y todo lo demás, y hacer a fuego lento el tiempo que marque el paquete de lentejas. \nUna vez hechas, retirar el laurel, la cebolla, las hierbas y los ajos.','\n',char(10)),'comida,carne,congelable,día antes,finde,legumbres,mirela,sin hidratos,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(14,'Tumbet','','comida,día antes,finde,frito,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(15,'Verduras cocidas','Cocer 20 minutos','cena,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(16,'Sopa',replace('Poner todo en la olla y cocer\nSacar el hueso de jamón a la hora o así para que no quede demasiado fuerte.','\n',char(10)),'acompañamiento,congelable,día antes',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(17,'Filetes empanados',replace('Poner los filetes en huevo\nEmpanar en pan rallado\nRebozar en aceite','\n',char(10)),'comida,carne,día antes,excursión,frito,mirela,rebozado,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(18,'Pasta carbonara',replace('Sofreír la cebolla en aceite, añadir el bacon cuando esté hecha, y luego la nata líquida (o huevo al estilo Mirela) y el parmesano. Mezclar con la pasta hervida.\n\nSi se quiere congelar la salsa, la proporción es unos 300 g cada 500 g de pasta','\n',char(10)),'comida,día antes,mirela,pasta,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(19,'Pasta con atún','Sofreír la cebolla, añadir el atún, y en seguida el tomate frito. Mezclar con la pasta hervida','comida,día antes,pasta,pescado,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(20,'Crema de calabaza',replace('Cortar la cebolla pequeña\nSofreírla a fuego lento hasta que se vuelva transparente. Cortar mientras tanto la calabaza/zanahoria/patata en trozos pequeños\nAñadir la calabaza/zanahoria/patata y dejarla unos minutos sofriendo\nAñadir la lenteja pelada, y añadir agua hasta que cubra\nHervir 20 minutos\nPoner en la trituradora con un poco del caldo, un poco de leche y los quesitos, triturar bien, y luego colar','\n',char(10)),'cena,día antes,mirela,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(21,'Muslos de pollo al horno',replace('Aceitar la bandeja del horno, y poner las patatas, saladas, en rodajas. \nPoner encima los muslos salpimentados. \nEn un mortero, machacar los ajos con las hierbas provenzales, un poco de aceite y el zumo de medio limón. \nPintar los muslos de pollo con la mezcla, apurar lo que quede con el vino blanco y verter el resto en la fuente. \nCortar el resto de limones en gajos finos, y ponerlos en los huecos que deje el pollo.\nCalentar el horno, y meter la fuente sin turbo, con resistencia superior e inferior, a 190 ºC. \nCocinar durante unos 50 minutos, dando la vuelta a los muslos a mitad de cocción. \nAl final, poner 5-10 minutos el grill por cada lado para que se dore. \nDesechar los gajos de limón, retirar los trozos de pollo y las patatas y pasar la salsa a una sartén, colándola (o triturándola para aprovechar la cebolla si se ha puesto). \nReducir hasta que espese añadiendo un poco de harina tamizada, y añadir al pollo y las patatas.','\n',char(10)),'comida,carne,congelable,día antes,horno,mirela,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(22,'Verduras salteadas congeladas',replace('Pelar y cortar todo en trozos de tamaño similar, y en un wok muy caliente ir salteando por orden según lo que necesite cada alimento para cocinarse. \nLo primero las zanahorias, judías verdes, coliflor y brócoli\nFinalmente el calabacín y la cebolla.\nAderezar con un poco de salsa de soja y sal, o hacer un picadillo previo con aceite de oliva/sésamo, ajo y perejil.','\n',char(10)),'acompañamiento,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(23,'Costillas al horno',replace('Salpimentar las costillas.\nEn un bol, mezclar el aceite, la miel, la mostaza y la salsa de soja con unas varillas. \nPintar las costillas por el lado de la carne y ponerlas en una fuente aceitada con el lado pintado hacia abajo. \nPintar el otro lado, y meter en el horno a 180 ºC (arriba y abajo, sin turbo) durante media hora. \nSacar, dar la vuelta, volver a pintar y meter media hora más, volviendo a pintar a los 15 minutos. \nFinalmente dorarlas con el grill.','\n',char(10)),'comida,carne,día antes,finde,horno,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(24,'Arroz a la cubana',replace('Hervir el arroz en la arrocera\nMientras tanto, sofreír la cebolla\nCuando esté hecha añadir la carne picada, y luego el tomate frito\nFreír los huevos, y servir todo junto','\n',char(10)),'comida,arroz,carne,día antes,huevos,plato único',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(25,'Falafel',replace('Poner en remojo los garbanzos en agua templada, y dejar 24h. \nCambiar el agua, y dejar 12-24h más. \nEscurrirlos bien, y triturarlos en batidora o similar, pero sin pasarse (si queda algún trozo grande no pasa nada). \nEn otro vaso picador, trituramos la cebolla cortada en cuartos, los dientes de ajo (quitándoles antes el germen central). Añadir también el comino, el cilantro, sal y la levadura. \nMezclar con los garbanzos hasta que quede una pasta homogénea. \nDejar reposar 1h, y empezar a hacer las croquetas: hacer bolitas del tamaño de una nuez con las dos manos, apretar bien para que suelten el líquido, volver a hacer una bola, y achatar para que queden con forma de “platillo volante”. Tampoco tiene que quedar muy dura, sino saldrán secas. Si la masa estuviera demasiado líquida, se le puede añadir harina de garbanzo. \nFreír en aceite de oliva suave, y servir con la salsa de yogur. \n\nSe pueden congelar antes de freírlos, así nos aseguramos de que no se deshacen.\n\nPara la salsa de yogur, mezclar en un bol el yogur natural, el diente de ajo picado muy pequeño, dos cucharadas de aceite de oliva virgen, el zumo de medio limón (o más al gusto), sal y pimienta y un poco de menta/hierbabuena. Si queda demasiado ácido, se puede poner un poco de azúcar. Remover bien, y ya está.','\n',char(10)),'comida,legumbres,rebozado,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(26,'Estofado de ternera',replace('Picar los ajos finos, ponerlos en aceite caliente, y marcar ahí la carne salpimentándola previamente. \nRetirar y, en el mismo aceite, freír la cebolla cortada pequeña.\nCuando esté hecha añadir el tomate pelado cortado muy pequeño, las patatas cortadas a dados (rompiéndolas en vez de cortar), las zanahorias en rodajas finas, los guisantes y los champiñones. \nCuando esté el sofrito, añadir la carne, el vaso de vino blanco y un chorro de brandy, y dejamos reducir 10-15 minutos.\nCubrir con el caldo, y cocer a fuego lento, con la olla tapada, durante 1h. \nDestapar y dejar media hora más hasta que reduzca.','\n',char(10)),'comida,carne,congelable,día antes,finde,mirela,plato único,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(27,'Hummus',replace('Meter todos los ingredientes en la batidora, y triturar hasta que quede una pasta fina. \nAjustar de comino/aceite/limón al gusto. \nMeter en la nevera, y servir frío.','\n',char(10)),'entrantes,legumbres,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(28,'Espárragos a la plancha','Cortar y freír','acompañamiento,mirela,sin hidratos,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(29,'Brócoli al horno',replace('Cortamos el brócoli en brotes pequeños y lo ponemos en una fuente para horno. \nAñadimos aceite, sal, pimienta y ajo y un poco de zumo de limón. \nMetemos al horno (180 ºC) durante 15 min con turbo, o 30 min calor arriba y abajo.','\n',char(10)),'acompañamiento,mirela,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(30,'Bistecs a la plancha','Salar y hacer a la plancha','cena,carne,rápido,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(31,'Croquetas','Hacer las croquetas','cena,frito,rápido,rebozado',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(32,'Ensalada','Cortar el tomate y la cebolla y mezclar. Se le puede poner lo que se quiera: pipas, pasas, queso feta...','acompañamiento,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(33,'Hamburguesas',replace('Triturar la cebolla con la batidora, hasta que quede una papilla.\n\nMezclar a mano la carne picada con la cebolla, el huevo, una cucharada de pan rallado y una cucharadita de sal hasta tener una pasta homogénea\n\nHacer las hamburguesas a mano (deberían salir unas 8), y cocinar en la freidora de aire 15 minutos a 180 C','\n',char(10)),'cena,carne,freidora aire,rápido,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(34,'Lasaña','','comida,carne,congelable,día antes,finde,horno,mirela,pasta,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(35,'Huevos rellenos',replace('Cocer los huevos\nPelarlos, sacar las yemas y reservarlas\nMezclar las yemas con el atún, la oliva machacada y la mayonesa, y ajustar de sal.\nRellenar las claras cocidas con el relleno, y poner un poco de mayonesa encima.\nMeter en la nevera y comer frío','\n',char(10)),'cena,día antes,huevos,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(36,'Pasta con piña y atún',replace('Hervir la pasta\nAñadir el atún, la piña y el jamón york cortados a trozos, y finalmente la mayonesa. \nGuardar en la nevera.','\n',char(10)),'comida,día antes,excursión,pasta,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(37,'Pasta al pesto','Hervir la pasta, mezclar con el pesto','comida,pasta,rápido,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(38,'Salchichas frescas','Hacer las salchichas a fuego no muy fuerte en una sartén tapada.','cena,carne,día antes,rápido,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(39,'Puré de patata',replace('Hervir las patatas enteras, 30 min aproximadamente. Sacarlas en seguida del agua. \nPelarlas, meterlas aún calientes en la amasadora cortadas a trozos y dejar que se vaya triturando\nIr añadiendo progresivamente la mantequilla (fría) para que se funda con las patatas aún calientes y la leche (caliente). No triturar demasiado o quedará pegajoso. \nPoner pimienta y rallar un poco de nuez moscada, y ajustar de sal','\n',char(10)),'acompañamiento,thermomix,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(40,'Tomate en ensalada',replace('Cortar todo junto. \nMezclar con queso (mozzarella o fresco), aguacate, o lo que se quiera.','\n',char(10)),'acompañamiento,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(41,'Tortilla francesa',replace('Batir huevos\nHacer en la sartén','\n',char(10)),'cena,huevos,rápido,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(42,'Ensaladilla',replace('Hervir los huevos y pelarlos.\nHervir las verduras\nCuando estén a temperatura ambiente, mezclarlo todo troceado, añadir el atún y mayonesa al gusto.\nMeter en la neveray comer frío','\n',char(10)),'comida,día antes,excursión,huevos,mirela,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(43,'Magdalenas de mantequilla',replace('Derretir la mantequilla en el microondas y dejar templar\n\nBatir los huevos junto con el azúcar hasta que espumen bien. Añadir la ralladura de limón, la mantequilla templada, el aceite y la leche. Batir de nuevo hasta que se se integren todos los ingredientes.\n\nIncorpora la harina junto con la levadura y la sal a través de un tamiz o colador. Guardar la mezcla en la nevera durante una hora, este paso es muy importante.\n\nColocar las cápsulas de magdalena dentro de cada una de las cavidades de una bandeja para cupcakes Llenar 3/4 partes de los moldes y espolvorear un poco de azúcar encima, muy poco.\n\nCalentar el horno a 220 ºC, y dejar 10 minutos. Bajar la temperatura a 200º C y hornear cinco minutos más. Antes de retirarlas del horno, comprobar pinchando con un palito de brocheta y si sale limpio, retirarlas del horno. Dejar enfriar encima de una rejilla.','\n',char(10)),'postres,horno,mirela',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(44,'Arroz blanco','Lavar arroz, poner en arrocera','acompañamiento,arroz,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(45,'Coles de Bruselas al horno',replace('Pelar las coles, partirlas por la mitad y ponerlas en una fuente para horno.\nSalpimentar, poner un chorro de aceite y la salsa de soja y rociar con limón. Remover bien.\nMeter en el horno a 220 C 20 minutos, removiendo a la mitad.','\n',char(10)),'acompañamiento,sin hidratos,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(46,'Salmón a la naranja',replace('Precalentar el horno a 180º, calor arriba y abajo (sin turbo). \nPoner en un cazo el zumo de una naranja, la miel, la mostaza y la salsa de soja, y poner al fuego en un cazo a fuego suave, para mezclar bien y que reduzca\nCortamos la naranja y el limón en rodajas muy finas y las ponemos en el fondo de una fuente de horno, espolvoreamos con un poco de eneldo.\nPonemos el salmón sobre las rodajas de cítricos, pintamos los lomos con la salsa, y repartimos la que quede por el resto de la fuente\nAñadimos un poco más de eneldo por encima. \nMeter en el horno 20 minutos.','\n',char(10)),'comida,día antes,horno,mirela,pescado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(47,'Yogures caseros',replace('Poner los botes de yogur vacíos en el horno, a 41 ºC\nSi es necesario, descongelar el yogur\nPoner la leche a fuego medio con el azúcar, hasta que llegue a 70 ºC. \nBajar el fuego suave (a 3) y dejar 10 minutos.\nDejar reposar hasta que la temperatura esté a 45 ºC\nAñadir el yogur, y batir bien con unas varillas\nPoner en las yogurteras, cerrar, y dejar 6h en el horno a 41 ºC\nComprobar que se ha solidificado (inclinando un yogur) y meter en la nevera 1-2 horas antes de comer','\n',char(10)),'postres,horno',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(48,'Galletas mantequilla','Mezclar todo, hacer masa y hacer galletas.','postres,horno,repostería',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(49,'Crespells',replace('Mezclar el aceite de oliva y la manteca con las manos, deshaciendo la manteca hasta que quede bien mezclado. \nAñadir el resto de los ingredientes, menos la harina, y volver a mezclar hasta que obtengamos una masa homogénea.\nAñadir la harina. Para amasar se puede hacer a mano o con robot de cocina y se deja reposar unos 15 minutos aproximadamente.\nA continuación, estirar la masa con un rodillo y con un grosor considerable y con los moldes de crespells (tiene forma de flor de 6 pétalos, corazón, etc.) hacemos las galletas que hornearemos durante 10 ó 15 minutos a 180 grados hasta que estén doradas.\nY para acabar, si os gusta, se pueden espolvorear con azúcar glas.','\n',char(10)),'repostería',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(50,'Pollo al horno con pimientos',replace('Ponemos los muslos del pollo limpios en un recipiente amplio, los embadurnamos con sal, romero y tomillo, les echamos los dientes de ajo a rodajitas y ponemos la pimienta recién molida.\nLe echamos el vino, los removemos que cojan todo el aliño y reservamos.\nPelamos, lavamos y cortamos a cuadraditos las patatas y les echamos algo de sal.\nLavamos el pimiento, cortamos igualmente a cuadraditos y reservamos.\nPreparamos una bandeja de horno pasándole aceite de oliva por toda la superficie (yo lo hago con brocha de silicona). Repartimos los trocitos de pimiento y patata y encima ponemos los muslos de pollo y el liquido de maceración y un vasito de agua (unos 150 ml.). Les echamos por encima un chorrito de aceite de oliva virgen extra, que le va a dar un toque especial. \nMetemos la fuente en el horno en posición media-baja, calor arriba y abajo (sin turbo), y dejar 50 minutos a 190 ºC, dando la vuelta a la mitad y añadiendo un poco de agua/vino si es necesario.','\n',char(10)),'comida,carne,día antes,por probar,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(51,'Cous cous','','comida,excursión,pasta,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(52,'Buñuelos de bacalao',replace('Deshacer el bacalao\nAñadir el huevo, mejor con la clara montada/batida\nAñadir la harina y la leche, poner un poco de sal y remover hasta que quede una pasta homogénea\nRebozar poniendo pegotes con una cuchara','\n',char(10)),'comida,frito,pescado,rebozado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(53,'Pimientos rojos al horno',replace('Poner los pimientos en una fuente de horno\nMeter en el horno a 180 C, 30 minutos\nDar la vuelta y dejar 30 minutos más','\n',char(10)),'acompañamiento,mirela,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(54,'Patatas panaderas al horno',replace('Pelar las patatas y cortarlas en rodajas de 3 mm de grosor (mejor con mandolina).\n\nCortar la cebolla en tiras finas.\n\nPoner las patatas junto con la cebolla, mezcladas, en una fuente para horno, de manera que no queden en muchas capas.\n\nPoner sal, echar un buen chorro de aceite y opcionalmente alguna hierba (eneldo) y remover con las manos para distribuirlo bien.\n\nTapar la fuente con papel de aluminio, y hornear 45 minutos a 180 ºC, turbo. Alternativamente se pueden hacer 10-12 minutos en microondas.\n\nDestapar, añadir el vino blanco, y cocinar 20 minutos o hasta que empiecen a estar doradas.','\n',char(10)),'acompañamiento',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(55,'Sushi',replace('Lavar el arroz hasta que el agua salga muy clara (mínimo 5 o 6 veces)\nCocer en la arrocera. Para la Hitachi, en modo Jasmine\nPreparar la mezcla de vinagre, azúcar y sal\nJuntar la mezcla con el arroz caliente, removiendo con espátula no metálica y abanicando hasta temperatura corporal (36-37 ºC)\nHacer los makis y demás','\n',char(10)),'comida,arroz,finde,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(56,'Huevos hervidos','Hervir','comida,huevos,rápido,sin hidratos,thermomix,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(57,'Fideos con costillas','','comida,carne,día antes,pasta,plato único,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(58,'Brócoli y coles de bruselas al horno',replace('Precalentar el horno a 240 ºC, calor arriba y abajo sin ventilador\nCortar las coles de bruselas por la mitad\nCortar el brócoli en ramilletes de más o menos el tamaño de las coles\nMezclar todo en un bol con sal, pimienta y el aceite\nPoner en la bandeja del horno papel de horno, y poner las verduras separadas, sin que estén apelotonadas. \nMeter 10 minutos, dar la vuelta y dejar 15 minutos más. Tienen que quedar doradas.','\n',char(10)),'acompañamiento,horno,mirela,por probar,sin hidratos,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(59,'Canelones','','comida,carne,día antes,horno,mirela,pasta,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(60,'Coliflor al horno',replace('Precalentamos el horno a 190ºC con calor arriba y abajo sin ventilación mientras preparamos la coliflor.\n\nTrocear la col en porciones, y ponerla en una bandeja de horno con papel encerado.\n\nLe rociamos el aceite, además del pimentón, la sal y pimienta al gusto, llevamos al horno precalentado, bajamos la temperatura a 180ºC y horneemos por 25 o 30 minutos.\n\nCuando notemos su corteza dorada es que está lista para retirarla. La servimos acompañada de limón y perejil fresco, que le darán un acabado delicioso.','\n',char(10)),'acompañamiento,horno,mirela,sin hidratos,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(61,'Calabacín al horno',replace('Poner a calentar el horno, 180 ºC con turbo\n\nLavar el calabacín\n\nCortar el calabacín en bastones del mismo tamaño\n\nImpregnar los trozos de calabacín con aceite, ajo, sal y pimienta\n\nColocar los bastones de calabacín en una bandeja de horno\n\nHornear durante unos 30 minutos a 180 ºC','\n',char(10)),'acompañamiento,horno,mirela,por probar,sin hidratos,trabajo,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(62,'Alitas de pollo','','comida,carne,día antes,mirela,sin hidratos',-1,'2026-03-19 16:36:49');
