INSERT INTO recipes VALUES(64,'Coca de yogur 1-2-3',replace('Batir los huevos\nAñadir el yogur, aceite, azúcar y harina, y remover bien\nAñadir el sobre de levadura\nHornear 35 minutos a 180 ºC aproximadamente. Comprobar con un cuchillo que está bien','\n',char(10)),'postres,mirela,repostería,thermomix',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(65,'Quesadillas de pollo',replace('Cortar la pechuga en tiras pequeñas, y pasar por la sartén, añadiendo especias para fajitas de pollo si se quiere\nPoner un poco de queso rallado en la mitad de una fajita, añadir un poco de pollo, y poner más queso, además de una loncha de gouda\nCerrar las fajitas, y pasarlas por una sartén caliente, hasta que el queso se funda y se cierren','\n',char(10)),'cena,rápido',-1,'2026-03-19 16:36:49');
