INSERT INTO recipes VALUES(71,'Bacalao al horno con tomate',replace('Poner el tomate triturado en una cazuela con brandy, sal y dejarlo 20 minutos a fuego medio\nHornear los pimientos\nEnharinar y freír el bacalao\nPoner en una bandeja de horno un par de cucharadas grandes de salsa, encima el bacalao, y cubrir con el resto. Poner el pimiento en tiras\nHornear 15-20 minutos a 175 ºC. Cuando falten 5 minutos, untar de ajo y perejil mezclados con aceite.','\n',char(10)),'comida,día antes,frito,horno,mirela,pescado,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(72,'Paella de carne con costillas',replace('1. Marcar la costilla con un poco de aceite. Retirar. \n2. Sofreír el pimiento, judías verdes y habas baby\n3. Añadir alcachofas y tomate pelado y cortado pequeño.\n4. Añadir las costillas y el garrofón y dejar un minuto\n5. Añadir el arroz y mezclar bien 1-2 minutos\n6. Añadir el caldo, poner a fuego fuerte hasta que hierva y ajustar de sal\n7. Bajar a fuego medio, y hacer el tiempo que diga el arroz\n8. Poner los últimos minutos a fuego fuerte si se quiere socarrat.','\n',char(10)),'comida,arroz,carne,día antes,finde,plato único,trabajo',-1,'2026-03-19 16:36:49');
