INSERT INTO recipes VALUES(87,'Espinacas con pasas y piñones',replace('Remojamos las pasas en agua durante media hora\nLavamos las espinacas y las reservamos\nTostamos los piñones y las pasas con un poco de aceite\nCuando los piñones estén dorados, añadimos las espinacas escurridas\nRehogamos las espinacas hasta que se evapore el agua, añadimos sal y las apartamos del fuego\nServimos las espinacas calentitas','\n',char(10)),'acompañamiento,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(88,'Acelgas cocidas',replace('Separar las hojas de las pencas\nRetirar las hebras de las pencas\nLavar y trocear las pencas y las hojas por separado\nHervir agua con sal y cocer las pencas de 5 a 8 minutos\nAñadir las hojas y cocer 2 minutos más\nEscurrir las acelgas\nLas acelgas ya cocidas se pueden tomar con aceite o utilizar en otras recetas','\n',char(10)),'acompañamiento,mirela,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
