INSERT INTO recipes VALUES(94,'Crema de coliflor',replace('Sofreír la cebolla\nAñadir patata, coliflor y zanahoria cortadas pequeñas\nCubrir y hervir 20 minutos\nTriturar bien','\n',char(10)),'cena,día antes,sin hidratos,verduras',-1,'2026-03-19 16:36:49');
