INSERT INTO recipes VALUES(98,'Muslos de pollo freidora aire',replace('Poner los 4 muslos en la freidora de aire, 2 abajo y 2 arriba en la rejilla. Sólo con sal, sin aceite.\nPoner programa de muslos de pollo','\n',char(10)),'comida,carne,freidora aire,rápido,sin hidratos,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(99,'Albóndigas en salsa',replace('Pica un diente de ajo y ponlo en un bol con la carne, el huevo, la miga de pan remojada en la leche, una cucharadita de perejil picado y un pellizco de sal. Mezcla hasta obtener una masa homogénea.\nForma las albóndigas pasándolas por harina y resérvalas. \nEn una sartén con aceite de oliva abundante, fríe las albóndigas hasta que se dore su exterior. (ALTERNATIVA: freídora de aire, 15 min a 180 ºC)\nSaca y reserva mientras elaboramos la salsa. \nPica dos dientes de ajo, la zanahoria y las dos cebollas, pochándolos en una sartén a fuego lento. \nAñade una cucharada de harina y el vino y reduce mientras vas removiendo. \nAgrega el caldo de pollo o de carne y cocina durante 15 a 20 minutos. \nTritura la salsa con la batidora y ponla en una cacerola. \nMete también las albóndigas y deja que el conjunto cueza durante diez minutos, apaga el fuego y tapa, dejando reposar unos minutos antes de comer.','\n',char(10)),'comida,carne,congelable,día antes,mirela,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(100,'Lasaña destroyer','Lasaña mega-power Mirela','comida,carne,día antes,mirela,pasta,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(101,'Crema de zanahoria y curry',replace('Ponga en el vaso la cebolla, la pasta de jengibre y triture 3 seg/vel 7. Con la espátula baje los ingredientes hacia el fondo del vaso.\nAgregue la mantequilla y sofría 4 min/120°C/vel 1.\nAgregue solo 1 cucharada de curry, las zanahorias y triture 5 seg/vel 5. Con la espátula baje los ingredientes hacia el fondo del vaso.\nSofría 5 min/120°C/vel 1.\nAgregue la manzana y triture 5 seg/vel 5. Con la espátula baje los ingredientes hacia el fondo del vaso.\nAgregue el agua, el concentrado de verduras, el concentrado de tomate, las hojas de laurel y cocine 40 min/100°C/vel 1.\nPrecaliente el horno a 200°C. Prepare una bandeja para horno con un papel para hornear. Reserve.\nMientras tanto, en un bol condimente los garbanzos con la pimienta, la sal, la cucharada de curry restante, el aceite y vierta en la bandeja para horno preparada. Hornee por 20 minutos (200°C) o hasta que los garbanzos estén crocantes. Retire y reserve.\nCon cuidado retire las hojas de laurel del vaso, agregue la crema de leche y triture 1 min/vel 5-8 progresivamente. Divida la sopa en pocillos individuales. Decore con un chorrito de crema, los garbanzos crocantes y una pizca de pimienta. Sirva inmediatamente.','\n',char(10)),'entrantes,día antes,sin hidratos,thermomix,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(102,'Crema de calabacín',replace('Coloque en el vaso la cebolla, los dientes de ajo y la mantequilla, pique 3 seg/vel 5. Baje los restos de las paredes del vaso con la espátula y sofría 5 min/110°C/vel 1.\nAñada la calabacita, el agua, el cubo de caldo de verdura (para 0,5L) o el concentrado de caldo de verdura y la pimienta molida, cocine 16 min/100°C/vel 1. Añada el queso crema, retire la tapa y deje reposar en el vaso hasta llegar a 70°C (aprox. 10 min).\nLicue Licuar /1 min aumentando progresivamente la velocidad. Rectifique sazón y sirva caliente.','\n',char(10)),'entrantes,día antes,sin hidratos,thermomix,verduras',-1,'2026-03-19 16:36:49');
