INSERT INTO recipes VALUES(114,'Brócoli al horno con queso feta, tomate cherry y limón','**Precalentamos el horno a 200º C**. Mientras se calienta, disponemos todos los ingredientes en una fuente grande: el brócoli cortado en ramilletes de un bocado, el tomate cherry en mitades, el queso feta en trozos grandes (nosotros hemos usado dos paquetes de 150 g partidos en cuatro), la cebolla cortada en juliana, las aceitunas deshuesadas, y medio limón cortado en rodajas. Espolvoreamos sobre la verdura el comino y el **chile en copos al gusto** (si no tenemos, podemos también moler un par de guindillas de cayena). Añadimos sal y pimienta negra reción molida y un buen chorretón de aceite de oliva. Cuando el horno esté caliente introducimos la bandeja a media altura, y dejamos que se cocinen las verduras entre 20 y 30 minutos, hasta que la piel de los tomates de resquebraje y el brócoli esté bien dorado. Servimos con el medio limón sobrante para quien quiera echar más y, si nos gusta, **un poco de cilantro fresco picado**.','acompañamiento,horno,por probar,rápido,verduras',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(115,'Chuletas de aguja a la plancha','','comida,carne,rápido,sin hidratos',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(116,'Costillas al Horno Súper Tiernas','This recipe is for super tender oven-baked ribs cooked low and slow. The recipe maintains the original marinade ingredients but changes the cooking method to ensure the meat is very tender.','comida,carne,finde,horno,por probar',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(117,'Quesadillas','','',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(118,'Arroz brut meloso',replace('Tostar la carcasa junto a la verdura, una vez tostado, añadir el vino blanco, reducir 30 segundos, añadir las 4 especies mallorquinas y el agua, cocinar el conjunto por espacio de 1 hora y media.\n\nCortar el butifarrón, el pimiento verde y la cebolleta en cubitos muy pequeños, agregar al cazo unas gotas de aceite y pochar el conjunto.\n\nAñadir el arroz y las especias.\n\nRecordad que medimos el arroz con un cazo en volumen.\n\nIremos añadiendo el volumen que hemos puesto de arroz, en caldo y la cantidad irá desde los 3 a 4 volúmenes, dependiendo si recordáis de la intensidad del fuego, hasta obtener la textura deseada, su tiempo de cocción está en 16-18 minutos, recordad que es el arroz de las mil vueltas y ojo fuego medio.','\n',char(10)),'comida,arroz,finde,por probar',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(119,'Estofado de aguja de cerdo al vino tinto',replace('Salpimenta los tacos de aguja.\n\nPásalos por harina y sacude bien para que solo quede una capa fina.\n\nEn la olla rápida, con un buen fondo de aceite caliente, dora la carne a fuego fuerte por todos sus lados. Retira la carne a un plato y reserva.\n\nEn el mismo aceite (si hay mucho, quita un poco), añade la cebolla, la zanahoria y el ajo.\n\nCocina a fuego medio-suave unos 10-12 minutos. Raspa el fondo con la cuchara de madera para soltar los jugos tostados de la carne. La cebolla debe quedar bien dorada, casi color caramelo.\n\nSube el fuego y vierte el vino tinto.\n\nDeja que hierva a borbotones durante 3 o 4 minutos sin tapa. Esto es vital para que se evapore el alcohol y la salsa no sepa &quot;agria&quot;.\n\nIntroduce la carne reservada en la olla.\n\nAñade la hoja de laurel, el tomillo y el caldo de carne (no hace falta cubrir la carne del todo).\n\nCierra la olla. Cuando suba la válvula (posición 2), baja el fuego al mínimo necesario para mantener la presión y cuenta 18 - 20 minutos.\n\nApaga el fuego y deja que la presión baje sola (unos 10-15 min). Esto hace que la carne no se asuste y quede más tierna.\n\nAbre la olla y saca los trozos de carne a una fuente. Busca y retira la hoja de laurel.\n\nTritura todo el contenido de la olla con la batidora hasta que quede una crema fina y brillante.\n\nVuelve a meter la carne en la salsa, dale un hervor de 1 minuto para que se amalgamen los sabores y ¡listo!','\n',char(10)),'comida,carne,congelable,día antes,trabajo',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(120,'Arroz Meloso de Solomillo y Butifarrón',replace('Pon el caldo en una olla aparte y manténlo a fuego suave. Debe estar hirviendo o a punto de hervir durante todo el proceso. Si echas caldo templado, el arroz se pasará por fuera y quedará crudo por dentro.\n\nEn una cazuela ancha, calienta un chorrito de aceite. Añade los dados de solomillo a fuego fuerte. Solo queremos dorarlos por fuera para que sellen sus jugos. Retira la carne a un plato y reserva (no la cocines del todo ahora).\n\nEn la misma grasa de la carne, baja el fuego a medio y añade la cebolleta y el pimiento verde. Cuando empiecen a estar transparentes, añade el butifarrón. Verás que el aceite se tiñe y empieza a oler de maravilla. Cocina 5 minutos más.\n\nEcha el arroz a la cazuela junto con las 4 especias. Remueve bien durante 1 o 2 minutos. El grano debe absorber la grasa del sofrito y ponerse traslúcido. Si vas a usar vino blanco, échalo ahora y deja que se evapore 30 segundos.','\n',char(10)),'comida,arroz,carne,finde,plato único',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(121,'Salmón teriyaki',replace('Hacer la salsa mezclando soja, miel, jengibre, ajo picado muy pequeño y un chorro de vinagre.\n\nPoner los lomos en una fuente y poner la mitad de la salsa. Rodear con ramilletes de brócoli con un chorro de aceite y sal.\n\nDejar reposar mientras calienta el horno a 180 C, calor arriba y abajo\n\nHornear durante 12 minutos\n\nPincelar con el resto de la salsa, y poner 8 minutos más\n\nServir con una base de arroz basmati o similar','\n',char(10)),'horno,pescado',-1,'2026-03-19 16:36:49');
INSERT INTO recipes VALUES(122,'Curry cremoso de pollo (Butter chicken - India)',replace('This recipe is designed for a specific device and accessory combination. Without this specific combination, the result is not guaranteed.\n\nMarinate the chicken with lemon juice, salt, pepper, sweet paprika, curry powder, ground cinnamon, and garlic powder.\n\nPrepare the sauce by combining chalots, garlic, fresh ginger, butter, homemade fried tomato, concentrated tomato, brown sugar, ground almond, and water.\n\nCook the chicken in the sauce.\n\nServe the creamy chicken curry garnished with fresh chopped cilantro.','\n',char(10)),'comida,arroz,carne,congelable,día antes,joan i guillem,por probar,sin hidratos,thermomix,trabajo',-1,'2026-03-19 16:36:49');
